package com.example.provenylab.product;
import com.fasterxml.jackson.core.JsonProcessingException; import com.fasterxml.jackson.databind.ObjectMapper; import org.springframework.jdbc.core.JdbcTemplate; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.time.Instant; import java.util.*;
@Service
public class ProductMintService {private final JdbcTemplate jdbc; private final ObjectMapper objectMapper; public ProductMintService(JdbcTemplate jdbc,ObjectMapper objectMapper){this.jdbc=jdbc;this.objectMapper=objectMapper;} @Transactional public Map<String,Object> mint(String serialNumber)throws JsonProcessingException{String passportId="psp-"+UUID.randomUUID();jdbc.update("INSERT INTO product_passport(passport_id,serial_number) VALUES (?,?)",passportId,serialNumber);enqueue(passportId,"MINT","ledger:"+passportId+":MINT",Map.of("passportId",passportId,"serialNumber",serialNumber,"eventAction","MINT"));return Map.of("passportId",passportId,"serialNumber",serialNumber,"ledgerStatus","PENDING");} @Transactional public Map<String,Object> transfer(String passportId,String toOwnerId)throws JsonProcessingException{Integer exists=jdbc.queryForObject("SELECT count(*) FROM product_passport WHERE passport_id=?",Integer.class,passportId);if(exists==null||exists==0)throw new IllegalArgumentException("passport not found: "+passportId);String eventId=UUID.randomUUID().toString();enqueue(passportId,"TRANSFER_COMPLETED","ledger:"+passportId+":TRANSFER:"+eventId,Map.of("passportId",passportId,"toOwnerId",toOwnerId,"eventAction","TRANSFER_COMPLETED"));return Map.of("passportId",passportId,"toOwnerId",toOwnerId,"ledgerStatus","PENDING");} private void enqueue(String passportId,String eventAction,String idempotencyKey,Map<String,Object> payload)throws JsonProcessingException{Map<String,Object> envelope=Map.of("passportId",passportId,"eventCategory","OWNERSHIP","eventAction",eventAction,"actorRole","BRAND","actorId","demo-actor","occurredAt",Instant.now().toString(),"schemaVersion",1,"idempotencyKey",idempotencyKey,"payload",payload);String json=objectMapper.writeValueAsString(envelope);jdbc.update("INSERT INTO outbox_event(aggregate_id,aggregate_type,event_type,payload,idempotency_key,status) VALUES (?,'PASSPORT',?,?::jsonb,?,'PENDING') ON CONFLICT (idempotency_key) DO NOTHING",passportId,eventAction,json,idempotencyKey);} }
